                // 1. Insertion: dp[i][j-1] + 1
                // 2. Deletion: dp[i-1][j] + 1
                // 3. Substitution: dp[i-1][j-1] + 1
                dp[i][j] = 1 + Math.min(
                    dp[i][j - 1],      // Insertion
                    dp[i - 1][j],      // Deletion
                    dp[i - 1][j - 1]   // Substitution
                );
            }
        }
    }

    return dp[m][n];
