function editDistance(a, b) {
    const m = a.length;
    const n = b.length;

    // Create a 2D DP array
    const dp = Array(m + 1).fill(null).map(() => Array(n + 1).fill(0));

    // Base cases: converting empty string to/from prefix of other string
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Fill in the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            if (a[i - 1] === b[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1]; // No operation needed
            } else {
                dp[i][j] = 1 + Math.min(
                    dp[i - 1][j],      // Deletion
                    dp[i][j - 1],      // Insertion
                    dp[i - 1][j - 1]   // Substitution
                );
            }
        }
    }

    return dp[m][n];
}
