/**
 * Calculates the Levenshtein distance between two strings.
 * The Levenshtein distance is the minimum number of single-character edits 
 * (insertions, deletions, or substitutions) required to change one word into the other.
 * 
 * @param {string} a The first string.
 * @param {string} b The second string.
 * @returns {number} The edit distance.
 */
const editDistance = (a, b) => {
    const m = a.length;
    const n = b.length;

    // Create a 2D array (m+1) x (n+1) for dynamic programming
    // dp[i][j] will store the edit distance between the first i characters of a 
    // and the first j characters of b.
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Base cases:
    // If b is empty, the distance is the length of a (all deletions)
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }

    // If a is empty, the distance is the length of b (all insertions)
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Fill the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            // Cost is 0 if characters match, 1 otherwise (substitution cost)
            const cost = (a[i - 1] === b[j - 1]) ? 0 : 1;

            // dp[i][j] is the minimum of three possibilities:
            // 1. Deletion: dp[i-1][j] + 1 (Delete a[i-1])
            // 2. Insertion: dp[i][j-1] + 1 (Insert b[j-1] into a)
            // 3. Substitution/Match: dp[i-1][j-1] + cost 
            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,          // Deletion
                dp[i][j - 1] + 1,          // Insertion
                dp[i - 1][j - 1] + cost    // Substitution or Match
            );
        }
    }

    // The result is stored in the bottom-right cell
    return dp[m][n];
};
