const groupAnagrams = (words) => {
  const anagramMap = new Map();
  const order = new Set();

  for (const word of words) {
    // Create a canonical key for anagrams by sorting the characters
    const sortedKey = word.split('').sort().join('');

    if (!anagramMap.has(sortedKey)) {
      // If this key is new, record its order based on the first appearance of its members
      order.add(sortedKey);
      anagramMap.set(sortedKey, []);
    }

    // Add the word to the corresponding group
    anagramMap.get(sortedKey).push(word);
  }

  // The problem requires preserving the input order for groups based on the first appearance of any member.
  // Since we iterate through 'words' in order, the first time we encounter a key, it represents the earliest
  // appearance of a word belonging to that anagram group.
  // We need to retrieve the keys in the order they were first inserted into the Map (which corresponds to the first appearance order).

  // However, Map iteration order preserves insertion order. If we iterate over anagramMap.entries(), 
  // the groups will be ordered by the first time a key was inserted.

  const result = [];
  for (const [key, group] of anagramMap.entries()) {
    result.push(group);
  }

  // A simpler way to ensure the order matches the first appearance of *any* member:
  // We can iterate through 'words' again, and if a word hasn't been assigned to a group yet,
  // we assign it to the correct group and add that group to our ordered result list.

  const finalGroups = [];
  const assignedWords = new Set();
  const groupKeys = new Set();

  for (const word of words) {
    if (assignedWords.has(word)) {
      continue;
    }

    const sortedKey = word.split('').sort().join('');
    const group = anagramMap.get(sortedKey);

    if (!groupKeys.has(sortedKey)) {
      // This is the first time we encounter a word belonging to this group in the input sequence.
      // Add the group to the final result array, preserving order.
      finalGroups.push(group);
      groupKeys.add(sortedKey);
    }

    // Mark all members of this group as seen to avoid duplicate group additions
    // Wait, the requirement is to preserve input order *within* the group, and order the *groups* by first appearance.
    // The structure of anagramMap already stores the words in the order they appeared for that group.

    // Let's stick to the Map iteration since JS Map preserves insertion order, and the first time a key
    // is inserted corresponds to the first word belonging to that group.

    const orderedGroups = [];
    for (const [key, group] of anagramMap.entries()) {
        orderedGroups.push(group);
    }
    return orderedGroups;
};
