const coinChange = (coins, amount) => {
    if (amount === 0) {
        return 0;
    }

    // dp[i] will be the minimum number of coins needed to make amount i
    // Initialize with amount + 1 (a value larger than any possible result)
    const dp = new Array(amount + 1).fill(amount + 1);

    // Base case: 0 amount requires 0 coins
    dp[0] = 0;

    for (let i = 1; i <= amount; i++) {
        for (const coin of coins) {
            if (i - coin >= 0) {
                // Update dp[i] with the minimum of its current value
                // and 1 (for the current coin) + minimum coins needed for the remaining amount (i - coin)
                dp[i] = Math.min(dp[i], 1 + dp[i - coin]);
            }
        }
    }

    // If dp[amount] is still amount + 1, it means the amount cannot be made
    return dp[amount] > amount ? -1 : dp[amount];
