        let newBoard = this.board.map(row => [...row]);
        let scoreIncrease = 0;

        if (dir === "left" || dir === "right") {
            for (let r = 0; r < 4; r++) {
                let row = this.board[r];
                let reversedRow = dir === "right" ? [...row].reverse() : [...row];

                let result = this._compress(reversedRow);

                let newRow = result.newLine.reverse();
                if (dir === "right") {
                    newRow = newRow.reverse();
                }

                // Update score and board
                scoreIncrease += result.scoreIncrease;
                newBoard[r] = newRow;
            }
        } else if (dir === "up" || dir === "down") {
            for (let c = 0; c < 4; c++) {
