                let col = [];
                for (let r = 0; r < 4; r++) {
                    col.push(this.board[r][c]);
                }

                let reversedCol = dir === "down" ? [...col].reverse() : [...col];

                let result = this._compress(reversedCol);

                let newCol = result.newLine.reverse();
                if (dir === "down") {
                    newCol = newCol.reverse();
