/**
 * @param {string[]} words
 * @return {string[][]}
 */
const groupAnagrams = (words) => {
    // Use a Map to store groups. Maps preserve insertion order of keys,
    // which naturally ensures the groups are ordered by the first appearance of their members.
    const anagramGroups = new Map();

    /**
     * Generates the canonical key for a word by sorting its characters.
     * @param {string} word
     * @returns {string}
     */
    const getCanonicalKey = (word) => {
        return word.split('').sort().join('');
    };

    for (const word of words) {
        const key = getCanonicalKey(word);

        if (!anagramGroups.has(key)) {
            // If the key is new, initialize the group
            anagramGroups.set(key, []);
        }

        // Append the word to the existing group (preserving input order within the group)
        anagramGroups.get(key).push(word);
    }

    // Return the values (the groups) from the map in their insertion order.
    return Array.from(anagramGroups.values());
};
