const lengthOfLongestSubstring = (s) => {
    let maxLength = 0;
    let start = 0;
    const charMap = new Map(); // Stores character -> index

    for (let end = 0; end < s.length; end++) {
        const char = s[end];

        if (charMap.has(char)) {
            // If the character is seen before, we must move the start of the window.
            // We take Math.max because the previous occurrence might be outside the current [start, end] window.
            start = Math.max(start, charMap.get(char) + 1);
        }

        // Update the last seen index of the current character
        charMap.set(char, end);

        // Calculate the current window length (end - start + 1) and update maxLength
        maxLength = Math.max(maxLength, end - start + 1);
    }

    return maxLength;
