const coinChange = (coins, amount) => {
    if (amount === 0) {
        return 0;
    }

    // dp[i] stores the minimum number of coins needed to make amount i
    // We use amount + 1 as a sentinel value, though Infinity works fine too.
    const MAX = amount + 1;
    const dp = new Array(amount + 1).fill(MAX);

    // Base case: 0 coins needed for amount 0
    dp[0] = 0;

    // Iterate through all amounts from 1 up to the target amount
    for (let i = 1; i <= amount; i++) {
        // Try every coin denomination
        for (const coin of coins) {
            // If the current coin can be used
            if (i - coin >= 0) {
                // Update dp[i] using the minimum of current value or (dp[i - coin] + 1)
                dp[i] = Math.min(dp[i], dp[i - coin] + 1);
            }
        }
    }

    // If dp[amount] is still MAX, it means the amount cannot be reached
    return dp[amount] === MAX ? -1 : dp[amount];
};
