/**
 * Calculates the Levenshtein distance (edit distance) between two strings.
 * The edit distance is the minimum number of single-character edits (insertions, deletions, or substitutions)
 * required to change one word into the other.
 *
 * @param {string} a The first string.
 * @param {string} b The second string.
 * @returns {number} The minimum edit distance.
 */
const editDistance = (a, b) => {
    const m = a.length;
    const n = b.length;

    // Create a 2D array (m+1) x (n+1)
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Initialize the first row and column
    // dp[i][0] represents the distance between a[0..i-1] and an empty string (i deletions)
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }

    // dp[0][j] represents the distance between an empty string and b[0..j-1] (j insertions)
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Fill the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            // Cost of substitution: 0 if characters match, 1 otherwise
            const cost = (a[i - 1] === b[j - 1]) ? 0 : 1;

            dp[i][j] = Math.min(
                // Deletion: dp[i-1][j] + 1
                dp[i - 1][j] + 1,
                // Insertion: dp[i][j-1] + 1
                dp[i][j - 1] + 1,
                // Substitution/Match: dp[i-1][j-1] + cost
                dp[i - 1][j - 1] + cost
            );
        }
    }

    // The bottom-right corner holds the total edit distance
    return dp[m][n];
};
