class Game2048 {
    constructor(board, spawnQueue) {
        // Deep copy the board
        this.board = board.map(row => [...row]);
        this.spawnQueue = [...spawnQueue];
        this.score = 0;
    }

    getBoard() {
        // Return a copy to prevent external modification
        return this.board.map(row => [...row]);
    }

    getScore() {
        return this.score;
    }

    /**
     * Checks if the game is over.
     * Game over if:
     * 1. No empty cells exist.
     * 2. No two adjacent tiles (H or V) have the same value.
     */
    isGameOver() {
        // Check for empty cells
        let hasEmpty = this.board.some(row => row.includes(0));
        if (hasEmpty) {
            return false;
        }

        // Check for adjacent equal tiles
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                const val = this.board[r][c];

                // Check horizontal adjacency
                if (c < 3 && val === this.board[r][c + 1]) {
                    return false;
                }
                // Check vertical adjacency
                if (r < 3 && val === this.board[r + 1][c]) {
                    return false;
                }
            }
        }

        return true; // No empty spots AND no adjacent matches
    }

    /**
     * Processes a single line (row or column) based on the direction.
     * @param {number[]} line - The array representing the line.
     * @param {string} dir - "left" or "right".
     * @returns {{newLine: number[], scoreIncrease: number}}
     */
    _processLine(line, dir) {
        let scoreIncrease = 0;
        let processed = [...line];

        // If moving right, reverse the line first, process as if moving left, then reverse back.
        if (dir === "right") {
            processed.reverse();
        }

        // --- Compression and Merging (always processing towards index 0) ---
        let newLine = [];
        let i = 0;
        while (i < 4) {
            let currentVal = processed[i];

            // Check for merge possibility
            if (i + 1 < 4 && currentVal === processed[i + 1] && currentVal !== 0) {
                let mergedVal = currentVal * 2;
                newLine.push(mergedVal);
                scoreIncrease += mergedVal;
                i += 2; // Skip both merged tiles
            } else {
                newLine.push(currentVal);
                i += 1;
            }
        }

        // Pad with zeros
        while (newLine.length < 4) {
            newLine.push(0);
        }

        // Reverse back if the original move was 'right'
        if (dir === "right") {
            newLine.reverse();
        }

        return { newLine, scoreIncrease };
    }

    move(dir) {
        const originalBoard = this.board.map(row => [...row]);
        let scoreIncrease = 0;
        let boardChanged = false;
        let newBoard = this.board.map(row => [...row]);

        const isVertical = (dir === "up" || dir === "down");

        if (isVertical) {
            // Transpose the board: rows become columns (i.e., iterate over columns)
            const transposed = Array(4).fill(0).map(() => Array(4).fill(0));
            for (let r = 0; r < 4; r++) {
                for (let c = 0; c < 4; c++) {
                    transposed[c][r] = this.board[r][c];
                }
            }

            // Process each column (which is now a row in 'transposed')
            for (let c = 0; c < 4; c++) {
                const column = transposed[c];
                const { newLine, scoreIncrease: lineScore } = this._processLine(column, dir);
                scoreIncrease += lineScore;

                // Update the transposed board
                for (let r = 0; r < 4; r++) {
                    transposed[c][r] = newLine[r];
                }
            }

            // Transpose back
            for (let r = 0; r < 4; r++) {
                for (let c = 0; c < 4; c++) {
                    newBoard[r][c] = transposed[c][r];
                }
            }

        } else { // Horizontal movement (Left or Right)
            // Process each row
            for (let r = 0; r < 4; r++) {
                const row = this.board[r];
                const { newLine, scoreIncrease: lineScore } = this._processLine(row, dir);
                scoreIncrease += lineScore;

                // Update the board
                for (let c = 0; c < 4; c++) {
                    newBoard[r][c] = newLine[c];
                }
            }
        }

        // 1. Check if the board actually changed
        let hasChanged = false;
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                if (newBoard[r][c] !== originalBoard[r][c]) {
                    hasChanged = true;
                    break;
                }
            }
            if (hasChanged) break;
        }

        if (hasChanged) {
            // 2. Apply changes
            this.board = newBoard;
            this.score += scoreIncrease;

            // 3. Spawn tile
            if (this.spawnQueue.length > 0) {
                const spawn = this.spawnQueue.shift();
                this.board[spawn.r][spawn.c] = spawn.v;
            }

            return true;
        } else {
            // No change, no spawn, no score change
            return false;
        }
    }
}
