    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        if (this.board[r][c] === 0) return false;
      }
    }

    // Check for adjacent equal tiles
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        // Check Right
        if (c < 3 && this.board[r][c] === this.board[r][c + 1]) return false;
        // Check Down
        if (r < 3 && this.board[r][c] === this.board[r + 1][c]) return false;
      }
    }
    return true;
  }

  move(dir) {
    const originalBoard = this.getBoard();
    const newBoard = this.getBoard();

    const processLine = (line) => {
      let result = [];
      let scoreGain = 0;
      let i = 0;

      // Step 1: Filter non-zero
      let nonZero = line.filter(val => val !== 0);

      // Step 2: Merge
      let mergedLine = [];
      for (let j = 0; j < nonZero.length; j++) {
        if (j < nonZero.length - 1 && nonZero[j] === nonZero[j + 1]) {
          let newVal = nonZero[j] * 2;
          mergedLine.push(newVal);
          scoreGain += newVal;
          j++; // Skip next because it merged
        } else {
          mergedLine.push(nonZero[j]);
        }
      }

      // Step 3: Pad with zeros
      while (mergedLine.length < 4) {
        mergedLine.push(0);
      }
      return { mergedLine, scoreGain };
    };

    if (dir === "left" || dir === "right") {
      for (let r = 0; r < 4; r++) {
        let line = (dir === "left") ? newBoard[r] : [...newBoard[r]].reverse();
        let { mergedLine, scoreGain } = processLine(line);
        this.score += scoreGain;
        if (dir === "left") {
          newBoard[r] = mergedLine;
        } else {
          newBoard[r] = [...mergedLine].reverse();
        }
      }
    } else {
      // up or down
      for (let c = 0; c < 4; c++) {
        let line = [];
        for (let r = 0; r < 4; r++) line.push(newBoard[r][c]);
        if (dir === "down") line.reverse();

        let { mergedLine, scoreGain } = processLine(line);
        this.score += scoreGain;

        if (dir === "up") {
          for (let r = 0; r < 4; r++) newBoard[r][c] = mergedLine[r];
        } else {
          for (let r = 0; r < 4; r++) newBoard[3 - r][c] = mergedLine[r];
        }
