function editDistance(a, b) {
  const m = a.length;
  const n = b.length;

  // Ensure n is the smaller length to minimize space complexity to O(min(m, n))
  if (m < n) {
    return editDistance(b, a);
  }

  // dp[j] will store the edit distance for the current prefix of a and prefix of b of length j
  const dp = Array.from({ length: n + 1 }, (_, i) => i);

  for (let i = 1; i <= m; i++) {
    let prevDiagonal = dp[0];
    dp[0] = i;
    for (let j = 1; j <= n; j++) {
      const temp = dp[j];
      if (a[i - 1] === b[j - 1]) {
        dp[j] = prevDiagonal;
      } else {
        dp[j] = 1 + Math.min(
          dp[j],        // Deletion from a
          dp[j - 1],    // Insertion into a
          prevDiagonal  // Substitution
        );
      }
      prevDiagonal = temp;
    }
  }

  return dp[n];
