function mergeIntervals(intervals) {
  if (!intervals || intervals.length === 0) return [];
  intervals.sort((a, b) => a[0] - b[0]);
  const merged = [];
  let cur = intervals[0];
  for (let i = 1; i < intervals.length; i++) {
    const [s, e] = intervals[i];
    if (s <= cur[1] + 1) {
      cur[1] = Math.max(cur[1], e);
    } else {
      merged.push([cur[0], cur[1]]);
      cur = [s, e];
    }
  }
  merged.push([cur[0], cur[1]]);
  return merged;
}
