function editDistance(a, b) {
    const n = a.length;
    const m = b.length;
    const dp = new Array(n + 1).fill(0);
    for (let i = 0; i <= n; i++) dp[i] = i;

    for (let j = 1; j <= m; j++) {
        const prev = dp[0];
        dp[0] = j;
        for (let i = 1; i <= n; i++) {
            const temp = dp[i];
            dp[i] = Math.min(
                dp[i] + 1,        // deletion
                dp[i - 1] + 1,    // insertion
                prev + (a[i - 1] === b[j - 1] ? 0 : 1) // substitution
            );
            prev = temp;
        }
    }
    return dp[n];
}
