class Game2048 {
    constructor(board, spawnQueue) {
        this.board = board.map(row => row.slice()); // copy
        this.score = 0;
        this.spawnQueue = spawnQueue;
    }
    getBoard() {
        return this.board;
    }
    getScore() {
        return this.score;
    }
    isGameOver() {
        // check for empty cells
        for (let r of this.board) if (r.includes(0)) return false;
        // check adjacent equal values
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                const v = this.board[r][c];
                if (c + 1 < 4 && this.board[r][c + 1] === v) return false;
                if (r + 1 < 4 && this.board[r + 1][c] === v) return false;
            }
        }
        return true;
    }
    move(dir) {
        const original = this.board.map(row => row.slice());
        const newBoard = this._slideBoard(dir);
        if (newBoard === original) return false;

        if (this.spawnQueue.length > 0) {
            const { r, c, v } = this.spawnQueue.shift();
            this.board[r][c] = v;
            this.score += v;
        }
        this.board = newBoard;
        return true;
    }
    _slideRow(row, dir) {
        if (dir === 'right') return this._slideRow(row.reverse(), 'left').reverse();
        const compressed = [];
        for (let v of row) if (v !== 0) compressed.push(v);
        const result = [];
        for (let i = 0; i < compressed.length; i++) {
            if (i + 1 < compressed.length && compressed[i] === compressed[i + 1]) {
                result.push(compressed[i] * 2);
                i++;
            } else {
                result.push(compressed[i]);
            }
        }
        while (result.length < 4) result.push(0);
        return result;
    }
    _slideBoard(dir) {
        const newBoard = Array(4).fill().map(() => [0, 0, 0, 0]);
        for (let r = 0; r < 4; r++) {
            if (dir === 'left') {
                newBoard[r] = this._slideRow(this.board[r], 'left');
            } else if (dir === 'right') {
                newBoard[r] = this._slideRow(this.board[r], 'right');
            } else if (dir === 'up') {
                const col = this.board.map(i => i[r]);
                const newCol = this._slideRow(col, 'up');
                for (let i = 0; i < 4; i++) newBoard[i][r] = newCol[i];
            } else if (dir === 'down') {
                const col = this.board.map(i => i[r]);
                const newCol = this._slideRow(col, 'down');
                for (let i = 0; i < 4; i++) newBoard[i][r] = newCol[i];
            }
        }
        return newBoard;
    }
}
